parameters.jsCode:
const rawPhone = String($json.phone ?? '').trim();
const instanceName = String($json.instanceName ?? '').trim();
const messageText = String($json.messageText ?? $json.text ?? '').trim();

const baseUrl = 'https://whatsapp.novian.com.br';
const role = 'AI Agent';
const writingDelayMs = 1200;
const linkPreview = false;
const status = 'Novo Lead';
const threadKind = 'lead';
const customData = { source: 'mariana-agent' };

const agentMap = {
  'mariana-sdr': 'Mariana Silva',
  'evolution_exchange': 'Mariana Silva'
};

if (!rawPhone) {
  throw new Error('Missing phone');
}

if (!instanceName) {
  throw new Error('Missing instanceName');
}

if (!messageText) {
  throw new Error('Missing messageText');
}

const phone = rawPhone.replace(/\D+/g, '');

if (!phone) {
  throw new Error('Invalid phone');
}

const threadId = `${phone}@s.whatsapp.net`;
const agent = String(agentMap[instanceName] ?? instanceName).trim();

return [{
  json: {
    phone,
    thread_id: threadId,
    messageText,
    instanceName,
    baseUrl,
    threadTitle: phone,
    agent,
    role,
    writingDelayMs,
    linkPreview,
    status,
    threadKind,
    customData
  }
}];

function esc(value) {
  if (value === null || value === undefined) return 'NULL';
  return `'${String(value).replace(/\\/g, '\\\\').replace(/'/g, "''")}'`;
}

function escTextArray(values) {
  const normalized = Array.isArray(values)
    ? values.filter((value) => typeof value === 'string' && value.trim()).map((value) => value.trim())
    : [];

  if (!normalized.length) {
    return "'{}'::text[]";
  }

  return `ARRAY[${normalized.map((value) => esc(value)).join(', ')}]::text[]`;
}

function escJson(value) {
  return `${esc(JSON.stringify(value ?? {}))}::jsonb`;
}

const input = $('Prepare WhatsApp Payload').first().json;
const sendResult = $('Send WhatsApp Message').first().json;

const providerMessageId = sendResult?.key?.id ?? null;
const providerStatus = sendResult?.message?.status ?? null;

const mergedCustomData = {
  ...(input.customData || {}),
  last_outbound_instance: input.instanceName,
  last_outbound_provider_message_id: providerMessageId,
  last_outbound_provider_status: providerStatus,
  last_outbound_writing_delay_ms: input.writingDelayMs,
  last_outbound_at: new Date().toISOString()
};

const sql = `WITH upsert_thread AS (
  INSERT INTO public.chat_threads (
    thread_id,
    title,
    preview,
    phone,
    unread,
    agent_ids,
    status,
    custom_data,
    thread_kind,
    last_message_at,
    updated_at
  ) VALUES (
    ${esc(input.thread_id)},
    ${esc(input.threadTitle)},
    ${esc(input.messageText)},
    ${esc(input.phone)},
    false,
    ${escTextArray([input.instanceName])},
    ${esc(input.status)},
    ${escJson(mergedCustomData)},
    ${esc(input.threadKind)},
    now(),
    now()
  )
  ON CONFLICT (thread_id) DO UPDATE
  SET
    title = CASE
      WHEN COALESCE(public.chat_threads.title, '') = '' THEN EXCLUDED.title
      ELSE public.chat_threads.title
    END,
    preview = EXCLUDED.preview,
    phone = COALESCE(EXCLUDED.phone, public.chat_threads.phone),
    unread = false,
    agent_ids = (
      SELECT ARRAY(
        SELECT DISTINCT item
        FROM unnest(
          COALESCE(public.chat_threads.agent_ids, '{}'::text[]) ||
          COALESCE(EXCLUDED.agent_ids, '{}'::text[])
        ) AS item
        WHERE item IS NOT NULL AND btrim(item) <> ''
      )
    ),
    status = COALESCE(public.chat_threads.status, EXCLUDED.status),
    custom_data = COALESCE(public.chat_threads.custom_data, '{}'::jsonb) || COALESCE(EXCLUDED.custom_data, '{}'::jsonb),
    thread_kind = COALESCE(public.chat_threads.thread_kind, EXCLUDED.thread_kind),
    last_message_at = now(),
    updated_at = now()
  RETURNING thread_id
)
INSERT INTO public.chat_messages (
  thread_id,
  agent,
  role,
  content,
  is_system
)
SELECT
  ${esc(input.thread_id)},
  ${esc(input.agent)},
  ${esc(input.role)},
  ${esc(input.messageText)},
  false
FROM upsert_thread
RETURNING id, thread_id, agent, role, content, is_system, created_at;`;

return [{
  json: {
    ...input,
    provider_message_id: providerMessageId,
    provider_status: providerStatus,
    provider_response: sendResult,
    persist_sql: sql
  }
}];

const prepared = $('Build Persistence SQL').first().json;
const dbRow = $json;

return [{
  json: {
    success: true,
    thread_id: prepared.thread_id,
    phone: prepared.phone,
    instanceName: prepared.instanceName,
    agent: prepared.agent,
    role: prepared.role,
    messageText: prepared.messageText,
    writingDelayMs: prepared.writingDelayMs,
    provider_message_id: prepared.provider_message_id,
    provider_status: prepared.provider_status,
    chat_message_id: dbRow.id ?? null,
    provider_response: prepared.provider_response
  }
}];
